dEventListener('storage',function(t){'daoessence_cart'===t.key&&updateCartBadge()});const modalStyles=document.createElement('style');modalStyles.textContent=`@keyframes slideInRight{from{opacity:0;transform:translateX(100px)}to{opacity:1;transform:translateX(0)}}@keyframes slideOutRight{from{opacity:1;transform:translateX(0)}to{opacity:0;transform:translateX(100px)}}.notification-close{background:none;border:none;color:#F5F0E6;font-size:18px;cursor:pointer;padding:0;line-height:1}.image-modal{position:fixed;top:0;left:0;right:0;bottom:0;z-index:2000;display:flex;align-items:center;justify-content:center;opacity:0;transition:opacity 0.3s ease}.image-modal.active{opacity:1}.image-modal .modal-overlay{position:absolute;top:0;left:0;right:0;bottom:0;background:rgba(26,22,18,0.8)}.image-modal .modal-content{position:relative;max-width:90%;max-height:90%}.image-modal .modal-content img{max-width:100%;max-height:80vh;border-radius:8px}.image-modal .modal-close{position:absolute;top:-40px;right:0;background:none;border:none;font-size:24px;cursor:pointer;color:#F5F0E6}.loading{position:fixed;top:0;left:0;right:0;bottom:0;z-index:2000;display:flex;flex-direction:column;align-items:center;justify-content:center;background:rgba(26,22,18,0.8);color:#F5F0E6}.loading-spinner{width:50px;height:50px;border:3px solid rgba(212,175,55,0.3);border-radius:50%;border-top-color:#D4AF37;animation:spin 1s ease-in-out infinite}.error-message{position:fixed;top:100px;left:50%;transform:translateX(-50%);background:#8B2500;color:#F5F0E6;padding:15px 25px;border-radius:4px;box-shadow:0 4px 15px rgba(0,0,0,0.2);z-index:10000;animation:slideInDown 0.3s ease-out}@keyframes spin{to{transform:rotate(360deg)}}@keyframes slideInDown{from{opacity:0;transform:translate(-50%,-50px)}to{opacity:1;transform:translate(-50%,0)}}`,document.head.appendChild(modalStyles);